/// Redaction helpers: never log secrets in production.
class Redactor {
  Redactor._();

  static const _secretKeys = <String>{
    'authorization',
    'auth',
    'token',
    'access_token',
    'refresh_token',
    'id_token',
    'password',
    'passcode',
    'pin',
    'secret',
    'client_secret',
    'api_key',
    'x-api-key',
    'cookie',
    'set-cookie',
    'session',
    'sessionid',
    'jwt',
  };

  static Object? redact(Object? value) {
    if (ProdLogger.includeSensitive) return value;
    if (value == null) return null;

    if (value is Map) {
      return value.map((k, v) {
        final key = k.toString().toLowerCase();
