          return MapEntry(k, '***REDACTED***');
        }
        return MapEntry(k, redact(v));
      });
    }

    if (value is List) {
      return value.map(redact).toList();
    }

    if (value is String) {
      return _redactInString(value);
    }

    return value;
  }

  static String _redactInString(String s) {
    var out = s;

    // Authorization: Bearer ...
    out = out.replaceAllMapped(
      RegExp(r'(?i)\bAuthorization\s*:\s*Bearer\s+([A-Za-z0-9\-\._~\+\/]+=*)'),
      (m) => '${m[0]!.split(':').first}: Bearer ***REDACTED***',
    );

    // Common query/body patterns
    out = out.replaceAllMapped(
      RegExp(r'(?i)\b(access_token|refresh_token|id_token|token|password|client_secret|secret)\b\s*[:=]\s*([^\s&,"}]+)'),
      (m) => '${m[1]}=***REDACTED***',
    );

    // JWT-like sequences
    out = out.replaceAllMapped(
      RegExp(r'\beyJ[a-zA-Z0-9_\-]+\.[a-zA-Z0-9_\-]+\.[a-zA-Z0-9_\-]+\b'),
      (_) => '***REDACTED_JWT***',
    );

    return out;
  }
}

