/// DB logging wrapper (generic). Call around your DB ops.
class DbLogger {
  DbLogger._();

  static Future<T> run<T>(
    String operation, {
    required FutureOr<T> Function() action,
    Map<String, dynamic>? meta,
  }) async {
    final id = _opId();
    final start = DateTime.now();
    ProdLogger.log(LogCategory.db, 'DB Start: $operation', data: {
      'id': id,
      'operation': operation,
      'meta': Redactor.redact(meta),
    });

    try {
      final result = await action();
      final ms = DateTime.now().difference(start).inMilliseconds;
      ProdLogger.log(LogCategory.db, 'DB Success: $operation', data: {
        'id': id,
        'durationMs': ms,
        'result': Redactor.redact(_stringifyResult(result)),
      });
      return result;
    } catch (e, st) {
      final ms = DateTime.now().difference(start).inMilliseconds;
      ProdLogger.log(LogCategory.error, 'DB Failure: $operation', data: {
        'id': id,
        'durationMs': ms,
        'meta': Redactor.redact(meta),
      }, error: e, stackTrace: st);
      rethrow;
    }
  }

  static String _opId() => DateTime.now().microsecondsSinceEpoch.toRadixString(16);

  static Object _stringifyResult(Object? r) {
    if (r == null) return 'null';
    if (r is String || r is num || r is bool) return r;
    return r.toString();
  }
}

