/// Navigator observer that logs route transitions.
class LoggingNavigatorObserver extends NavigatorObserver {
  @override
  void didPush(Route<dynamic> route, Route<dynamic>? previousRoute) {
    super.didPush(route, previousRoute);
    UiLogger.screen(_name(route), props: {
      'event': 'push',
      'from': previousRoute != null ? _name(previousRoute) : null,
      'to': _name(route),
    });
  }

  @override
  void didPop(Route<dynamic> route, Route<dynamic>? previousRoute) {
    super.didPop(route, previousRoute);
    UiLogger.screen(_name(previousRoute), props: {
      'event': 'pop',
      'from': _name(route),
      'to': previousRoute != null ? _name(previousRoute) : null,
    });
  }

  @override
  void didReplace({Route<dynamic>? newRoute, Route<dynamic>? oldRoute}) {
    super.didReplace(newRoute: newRoute, oldRoute: oldRoute);
    UiLogger.screen(_name(newRoute), props: {
      'event': 'replace',
      'from': oldRoute != null ? _name(oldRoute) : null,
      'to': newRoute != null ? _name(newRoute) : null,
    });
  }

  String _name(Route<dynamic>? r) {
    if (r == null) return 'null';
    return r.settings.name ?? r.runtimeType.toString();
  }
}

/// Global app health monitoring.
class AppHealthLogging {
  AppHealthLogging._();

  static void install({
    bool enable = kDebugMode,
    bool includeSensitive = false,
    bool logFlutterErrors = true,
    bool logPlatformDispatcherErrors = true,
    bool logHttpOverrides = false,
    bool logLifecycle = true,
  }) {
    ProdLogger.enabled = enable;
    ProdLogger.includeSensitive = includeSensitive;

    if (logFlutterErrors) {
      FlutterError.onError = (FlutterErrorDetails details) {
        ProdLogger.log(
          LogCategory.error,
          'FlutterError',
          error: details.exception,
          stackTrace: details.stack,
          data: {
            'library': details.library,
            'context': details.context?.toDescription(),
            'information': details.informationCollector?.call().map((n) => n.toString()).toList(),
          },
        );
      };
    }

    if (logPlatformDispatcherErrors) {
      PlatformDispatcher.instance.onError = (Object error, StackTrace stack) {
        ProdLogger.log(LogCategory.error, 'Uncaught Zone Error', error: error, stackTrace: stack);
        return false;
      };
    }

    if (logHttpOverrides) {
      HttpOverrides.global = _LoggingHttpOverrides();
    }

    if (logLifecycle) {
      WidgetsBinding.instance.addObserver(_LifecycleObserver());
    }

    SchedulerBinding.instance.addTimingsCallback((timings) {
      for (final t in timings) {
        ProdLogger.log(LogCategory.app, 'Frame Timing', data: {
          'vsyncOverheadMs': t.vsyncOverhead.inMicroseconds / 1000.0,
          'buildDurationMs': t.buildDuration.inMicroseconds / 1000.0,
          'rasterDurationMs': t.rasterDuration.inMicroseconds / 1000.0,
          'totalSpanMs': t.totalSpan.inMicroseconds / 1000.0,
        });
      }
    });

    ProdLogger.log(LogCategory.app, 'AppHealthLogging installed', data: {
      'enabled': ProdLogger.enabled,
      'includeSensitive': ProdLogger.includeSensitive,
    });
  }
}

