class _LoggingHttpOverrides extends HttpOverrides {
  @override
  HttpClient createHttpClient(SecurityContext? context) {
    final client = super.createHttpClient(context);
    client.connectionTimeout = const Duration(seconds: 30);

    client.addRequestModifier((HttpClientRequest req) {
      ProdLogger.log(LogCategory.http, 'Dart IO HTTP Request', data: {
        'method': req.method,
        'uri': req.uri.toString(),
        'headers': Redactor.redact(_headersToMap(req.headers)),
      });
      return req;
    });

    client.addResponseModifier((HttpClientResponse res) {
      ProdLogger.log(LogCategory.http, 'Dart IO HTTP Response', data: {
        'statusCode': res.statusCode,
        'reasonPhrase': res.reasonPhrase,
        'headers': Redactor.redact(_headersToMap(res.headers)),
      });
      return res;
    });

    return client;
  }

  static Map<String, String> _headersToMap(HttpHeaders headers) {
    final m = <String, String>{};
    headers.forEach((name, values) {
      m[name] = values.join(', ');
    });
    return m;
  }
}

